"""
gerar_historico.py
==================================================================
Recria o repositorio com 12 commits semanticos datados, usando apenas Python.
COMO USAR (no Windows, dentro de uma PASTA VAZIA):
    1) Coloque este arquivo na pasta vazia.
    2) Abra o terminal nessa pasta e rode:
         python gerar_historico.py
    3) Siga as instrucoes que aparecem no final.
==================================================================
"""
import base64
import os
import subprocess
import sys

def git(*args, env=None):
    res = subprocess.run(["git", *args], env=env,
                         stdout=subprocess.PIPE, stderr=subprocess.PIPE)
    if res.returncode != 0:
        msg = res.stderr.decode("utf-8", "replace").strip()
        # alguns comandos retornam !=0 sem ser erro fatal; mostra e segue
        if "nothing to commit" not in msg:
            print("AVISO git:", " ".join(args), "->", msg)
    return res

def write_b64(path, b64):
    pasta = os.path.dirname(path)
    if pasta:
        os.makedirs(pasta, exist_ok=True)
    with open(path, "wb") as f:
        f.write(base64.b64decode(b64.encode("ascii")))

def main():
    # Confirma que git existe
    try:
        subprocess.run(["git", "--version"], stdout=subprocess.DEVNULL,
                       stderr=subprocess.DEVNULL, check=True)
    except Exception:
        print("ERRO: Git nao encontrado. Instale em https://git-scm.com/download/win")
        sys.exit(1)

    git("init")
    # Garante identidade (so define se ainda nao houver)
    r = subprocess.run(["git", "config", "user.name"],
                       stdout=subprocess.PIPE, stderr=subprocess.PIPE)
    if not r.stdout.strip():
        git("config", "user.name", "Aluno UniFECAF")
        git("config", "user.email", "aluno@example.com")

    for i, (msg, data, arquivos) in enumerate(COMMITS, 1):
        for caminho, b64 in arquivos:
            write_b64(caminho, b64)
        git("add", "-A")
        env = dict(os.environ)
        env["GIT_AUTHOR_DATE"] = data
        env["GIT_COMMITTER_DATE"] = data
        git("commit", "-q", "-m", msg, env=env)
        print(f"  [{i}/12] {msg}")

    git("branch", "-M", "main")

    print("")
    print("=" * 60)
    print("Pronto! Repositorio recriado com 12 commits.")
    print("Veja com:  git log --oneline")
    print("=" * 60)
    print("")
    print("AGORA CONECTE AO SEU REPOSITORIO NO GITHUB:")
    print("  git remote add origin https://github.com/t1ctack/gerenciadorTarefasTechflow.git")
    print("  git push -u origin main --force")
    print("")
    print("(O --force substitui o commit antigo 'subindo arquivos' pelo")
    print(" historico completo. E seguro: os arquivos sao os mesmos.)")

